script.text:
      /* <flatten type="Javascript"> */
function active$Filter$LaborContract(f) {f.add_onResponseComplete(on$Filter$LaborContract$ResponseComplete);}
function close$Filter$LaborContract(f) {try {f.remove_onResponseComplete(on$Filter$LaborContract$ResponseComplete);} catch (ex) {}}
function onchange$Filter$LaborContract$Deparment(o) {o.parentForm.request('Reference', 'Reference', ['ma_bp']);}
function on$Filter$LaborContract$ResponseComplete(f, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Reference':
      f.setItemControlBehavior('bp_ref', result[0].Value, true);
      break;
    case 'Checking':
      var g = f.grid, k = [];
      if (f.getItemValue('ngay_ky_tu')) Array.add(k, {Name: 'ngay_ky_hd', Opr: '>=', Value: f.getItemValue('ngay_ky_tu'), Type: 'DateTime', Ignore: false});
      if (f.getItemValue('ngay_ky_den')) Array.add(k, {Name: 'ngay_ky_hd', Opr: '<=', Value: f.getItemValue('ngay_ky_den'), Type: 'DateTime', Ignore: false});
      if (f.getItemValue('ngay_tu')) Array.add(k, {Name: 'ngay_vao', Opr: '>=', Value: f.getItemValue('ngay_tu'), Type: 'DateTime', Ignore: false});
      if (f.getItemValue('ngay_den')) Array.add(k, {Name: 'ngay_vao', Opr: '<=', Value: f.getItemValue('ngay_den'), Type: 'DateTime', Ignore: false});

      if (f.getItemValue('ma_bp')) Array.add(k, {Name: 'bp_ref', Opr: 'like', Value: $func.trim(f.getItemValue('bp_ref')) + '%', Type: 'String', Ignore: false});
      if (f.getItemValue('ma_nv')) Array.add(k, {Name: 'ma_nv', Opr: '=', Value: f.getItemValue('ma_nv'), Type: 'String', Ignore: false});
      if (f.getItemValue('vi_tri')) Array.add(k, {Name: 'vi_tri', Opr: '=', Value: f.getItemValue('vi_tri'), Type: 'String', Ignore: false});
      if (f.getItemValue('ma_bac')) Array.add(k, {Name: 'ma_bac', Opr: '=', Value: f.getItemValue('ma_bac'), Type: 'String', Ignore: false});
      g.set_externalKey(k);
      break;
    default:
      break;
  }
}
/* </flatten> */
